+            .buf = buf.ptr,
+            .len = buf.len,
+        };
+    }
+
+    pub fn initReadonly(buf: []const u8) Py_buffer {
+        return .{
+            .buf = @constCast(buf.ptr),
+            .len = buf.len,
+            .readonly = true,
+        };
