+    pub fn set_args(self: *ArgParser, args: []const Arg) void {
+        self.args = args;
+    }
+
+    pub fn set_kwarg(self: *ArgParser, name: []const u8, value: Arg) !void {
+        try self.kwargs.put(name, value);
