+            self.futures.deinit();
+        }
+
+        pub fn add(self: *Self, future: *CancellableFuture(T)) !void {
+            try self.futures.append(future);
+        }
+
+        pub fn cancelAll(self: *Self, reason: CancelReason) usize {
+            if (self.cancelled) return 0;
