+            var cancelled_count: usize = 0;
+            for (self.futures.items) |future| {
+                const result = future.cancel(CancelOptions.withReason(reason));
+                if (result.success) {
+                    cancelled_count += 1;
+                }
+            }
+            return cancelled_count;
+        }
+
