+/// A lock-free bounded queue using atomic operations
+pub fn ConcurrentQueue(comptime T: type, comptime capacity: usize) type {
+    return struct {
+        const Self = @This();
+
+        buffer: [capacity]?T,
+        head: std.atomic.Value(usize),
+        tail: std.atomic.Value(usize),
+        size: std.atomic.Value(usize),
