+            if ((self.colors.get(obj) orelse WHITE) == WHITE) {
+                self.dfs(obj);
+            }
+        }
+
+        return self.cycles_found;
+    }
+
+    fn dfs(self: *Self, obj: *GCHeader) void {
+        self.colors.put(obj, GRAY) catch return;
